import { useMemo } from 'react';
import { readHistory } from '../../state/history.js';
import './stats.css';

function formatMmSs(ms: number): string {
  const s = Math.floor(ms / 1000);
  const m = Math.floor(s / 60);
  const sec = s % 60;
  return `${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
}

interface StatsPanelProps {
  onClose: () => void;
}

export function StatsPanel({ onClose }: StatsPanelProps) {
  // O(D) where D = distinct deals played. localStorage reads are O(1).
  const stats = useMemo(() => {
    const h = readHistory();
    const deals = Object.values(h.playedDeals);
    const totalDeals = deals.length;
    const totalWins = h.totalWins;
    const winRate = totalDeals > 0 ? Math.round((totalWins / Math.max(totalDeals, totalWins)) * 100) : 0;

    let bestTimeAny = Infinity;
    let totalTimeMs = 0;
    let totalMoves = 0;
    for (const d of deals) {
      if (d.bestTimeMs < bestTimeAny) bestTimeAny = d.bestTimeMs;
      totalTimeMs += d.bestTimeMs * d.wins;
      totalMoves += d.bestMoves * d.wins;
    }
    const avgTimeMs = totalWins > 0 ? Math.round(totalTimeMs / totalWins) : 0;
    const avgMoves = totalWins > 0 ? Math.round(totalMoves / totalWins) : 0;

    return {
      totalWins,
      totalDeals,
      winRate,
      bestTimeAny: bestTimeAny === Infinity ? null : bestTimeAny,
      avgTimeMs,
      avgMoves,
      streak: h.daily.streak,
      longestStreak: h.daily.longestStreak,
      completedDailies: h.daily.completedDays.length,
      bestTimeMs: h.bestTimeMs,
      bestMoves: h.bestMoves,
    };
  }, []);

  return (
    <div
      className="ce-stats-backdrop"
      role="dialog"
      aria-modal="true"
      aria-label="Personal statistics"
      onClick={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
      data-testid="cellar-stats"
    >
      <div className="ce-stats">
        <button className="ce-stats-close" aria-label="Close stats" onClick={onClose}>
          ×
        </button>
        <h2 className="ce-stats-title">Personal stats</h2>

        <div className="ce-stats-grid">
          <Stat label="Wins" value={String(stats.totalWins)} />
          <Stat label="Played" value={String(stats.totalDeals)} />
          <Stat label="Win rate" value={`${stats.winRate}%`} />
          <Stat
            label="Best time"
            value={stats.bestTimeAny !== null ? formatMmSs(stats.bestTimeAny) : '—'}
          />
          <Stat
            label="Avg time"
            value={stats.avgTimeMs > 0 ? formatMmSs(stats.avgTimeMs) : '—'}
          />
          <Stat
            label="Avg moves"
            value={stats.avgMoves > 0 ? String(stats.avgMoves) : '—'}
          />
          <Stat label="Daily streak" value={`${stats.streak} 🔥`} />
          <Stat label="Longest streak" value={String(stats.longestStreak)} />
          <Stat
            label="Dailies solved"
            value={String(stats.completedDailies)}
          />
        </div>

        <section className="ce-stats-section">
          <h3>Best by difficulty</h3>
          <table className="ce-stats-table">
            <thead>
              <tr>
                <th scope="col">Bracket</th>
                <th scope="col">Best time</th>
                <th scope="col">Best moves</th>
              </tr>
            </thead>
            <tbody>
              {(['easy', 'standard', 'hard', 'master'] as const).map((b) => (
                <tr key={b}>
                  <th scope="row">{b}</th>
                  <td>
                    {stats.bestTimeMs[b] !== undefined ? formatMmSs(stats.bestTimeMs[b]!) : '—'}
                  </td>
                  <td>{stats.bestMoves[b] !== undefined ? stats.bestMoves[b] : '—'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>

        <p className="ce-stats-hint">
          Stats live in your browser only — Cellar never sends them anywhere.
        </p>
      </div>
    </div>
  );
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div className="ce-stats-cell">
      <div className="ce-stats-cell-value">{value}</div>
      <div className="ce-stats-cell-label">{label}</div>
    </div>
  );
}

export function resetStats(): void {
  try {
    localStorage.removeItem('bilko_cellar_history_v1');
  } catch {}
}
